const parts = [$.input.businessType, $.input.location];
const staticTerms = "{{}} in {{}} contact email website";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

const results = $.steps.searchBusinesses.response.results || [];
const maxResults = parseInt($.input.maxResults || '10', 10);

// Deduplicate by hostname and filter out aggregator sites
const seen = new Set();
const skipDomains = ['yelp.com', 'yellowpages.com', 'facebook.com', 'linkedin.com', 'instagram.com', 'twitter.com', 'maps.google.com', 'tripadvisor.com', 'bbb.org', 'mapquest.com'];

const businesses = results.filter(r => {
  try {
    const hostname = new URL(r.url).hostname.replace('www.', '');
    if (seen.has(hostname)) return false;
    if (skipDomains.some(d => hostname.includes(d))) return false;
    seen.add(hostname);
    return true;
  } catch(e) { return false; }
}).slice(0, maxResults);

const urls = businesses.map(b => b.url);
const businessInfo = businesses.map((b, i) => ({ index: i + 1, title: b.title || '', url: b.url, snippet: (b.text || '').slice(0, 200) }));

return { urls, businessInfo, totalFound: results.length, selectedCount: urls.length };

const businessInfo = $.steps.selectUrls.output.businessInfo;
const iterations = $.steps.scrapeWebsites.response.iterations || [];
const urls = $.steps.selectUrls.output.urls;

let scrapedData = '';
iterations.forEach((iter, i) => {
  const url = urls[i] || 'Unknown';
  const info = businessInfo[i] || {};
  const resp = (iter.scrapeSite && iter.scrapeSite.response && iter.scrapeSite.response.data) ? iter.scrapeSite.response.data : {};
  const md = resp.markdown || '';

  scrapedData += '=== BUSINESS ' + (i + 1) + ' ===\n';
  scrapedData += 'URL: ' + url + '\n';
  scrapedData += 'Title: ' + (info.title || '') + '\n';
  scrapedData += 'Search snippet: ' + (info.snippet || '') + '\n';
  scrapedData += 'Page content:\n' + md.slice(0, 2500) + '\n\n';
});

return { scrapedData, scrapedCount: iterations.length };

const businessType = $.input.businessType;
const location = $.input.location;
const data = $.steps.compileScrapedData.output;

let prompt = 'You are a B2B lead generation specialist. Extract contact emails and business details from the scraped website data below. Only include REAL business email addresses (no generic noreply@, info@ only if no better option exists).\n\n';
prompt += 'BUSINESS TYPE: ' + businessType + '\n';
prompt += 'LOCATION: ' + location + '\n\n';
prompt += 'SCRAPED WEBSITE DATA:\n\n';
prompt += data.scrapedData + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract all email addresses found on each page\n';
prompt += '- Determine if the email is likely a decision-maker, general inquiry, or support email\n';
prompt += '- Extract phone numbers, physical addresses, and owner/staff names if visible\n';
prompt += '- Rate lead quality: A (decision-maker email found), B (general business email), C (no email, only phone/address)\n';
prompt += '- Filter out image file extensions (.png, .jpg, .gif, .jpeg) from email-like strings\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "leads": [\n';
prompt += '    {\n';
prompt += '      "businessName": "name of the business",\n';
prompt += '      "website": "URL",\n';
prompt += '      "emails": [{ "address": "email@example.com", "type": "owner/general/support", "confidence": "high/medium/low" }],\n';
prompt += '      "phone": "phone number or null",\n';
prompt += '      "address": "physical address or null",\n';
prompt += '      "contactNames": ["name if found"],\n';
prompt += '      "leadGrade": "A/B/C",\n';
prompt += '      "notes": "relevant context about the business"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "summary": { "total": 0, "withEmail": 0, "gradeA": 0, "gradeB": 0, "gradeC": 0 }\n';
prompt += '}\n';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { leads: [], summary: { total: 0, withEmail: 0 }, text: raw }; }

const ai = $.steps.parseAI.output;
const leads = ai.leads || [];
const date = new Date().toISOString().split('T')[0];

const sheetData = leads.map((lead, i) => {
  const primaryEmail = (lead.emails && lead.emails.length) ? lead.emails[0].address : '';
  const allEmails = (lead.emails || []).map(e => e.address).join(', ');
  const emailTypes = (lead.emails || []).map(e => e.address + ' (' + e.type + ')').join(', ');

  return {
    '#': i + 1,
    'Business Name': lead.businessName || '',
    'Website': lead.website || '',
    'Primary Email': primaryEmail,
    'All Emails': allEmails,
    'Email Details': emailTypes,
    'Phone': lead.phone || '',
    'Address': lead.address || '',
    'Contact Names': (lead.contactNames || []).join(', '),
    'Lead Grade': lead.leadGrade || 'C',
    'Notes': lead.notes || '',
    'Date Scraped': date
  };
});

return { sheetData, leadCount: leads.length, summary: ai.summary || {} };
